query MediaFilesConnectionBaseline(
  $first: Int!
  $after: String
  $query: String
  $sortKey: FileSortKeys
) {
  filesBaseline: files(first: $first, after: $after, query: $query, sortKey: $sortKey) {
    edges {
      cursor
      node {
        __typename
        id
        alt
        createdAt
        updatedAt
        fileStatus
        ... on MediaImage {
          image { url width height }
          preview { image { url width height } }
        }
        ... on GenericFile { url }
        ... on Video {
          preview { image { url width height } }
          sources { url mimeType format height width }
        }
        ... on ExternalVideo {
          embeddedUrl
          host
          originUrl
          preview { image { url width height } }
        }
        ... on Model3d {
          preview { image { url width height } }
          sources { url mimeType format filesize }
        }
      }
    }
    pageInfo { hasNextPage hasPreviousPage startCursor endCursor }
  }
}

query SellingPlanGroupsConnectionWindow(
  $first: Int
  $after: String
  $last: Int
  $before: String
  $query: String
  $sortKey: SellingPlanGroupSortKeys
  $reverse: Boolean!
) {
  sellingPlanGroupsWindow: sellingPlanGroups(
    first: $first
    after: $after
    last: $last
    before: $before
    query: $query
    sortKey: $sortKey
    reverse: $reverse
  ) {
    edges {
      cursor
      node {
        __typename
        id
        appId
        name
        merchantCode
        description
        options
        position
        createdAt
        productsCount { count precision }
        productVariantsCount { count precision }
        sellingPlans(first: 31) {
          edges {
            cursor
            node {
              __typename
              id
              name
              description
              options
              position
              category
              createdAt
              billingPolicy {
                __typename
                ... on SellingPlanRecurringBillingPolicy { interval intervalCount minCycles maxCycles }
              }
              deliveryPolicy {
                __typename
                ... on SellingPlanRecurringDeliveryPolicy { interval intervalCount cutoff intent preAnchorBehavior }
              }
              inventoryPolicy { reserve }
              pricingPolicies {
                __typename
                ... on SellingPlanFixedPricingPolicy {
                  adjustmentType
                  adjustmentValue {
                    __typename
                    ... on SellingPlanPricingPolicyPercentageValue { percentage }
                    ... on MoneyV2 { amount currencyCode }
                  }
                }
                ... on SellingPlanRecurringPricingPolicy {
                  afterCycle
                  createdAt
                  adjustmentType
                  adjustmentValue {
                    __typename
                    ... on SellingPlanPricingPolicyPercentageValue { percentage }
                    ... on MoneyV2 { amount currencyCode }
                  }
                }
              }
            }
          }
          pageInfo { hasNextPage hasPreviousPage startCursor endCursor }
        }
      }
    }
    pageInfo { hasNextPage hasPreviousPage startCursor endCursor }
  }
}

